const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
if (!m) return null; 

let dt = new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));

dt.setDate(dt.getDate() + 364);

const y = dt.getFullYear();
const mo = String(dt.getMonth() + 1).padStart(2, "0");
const d  = String(dt.getDate()).padStart(2, "0");
return `${y}-${mo}-${d}`;

(function () {
  const sel = '[selector="moneda-cop"] input[name="frm_ingresos_operaciones_anuales"]';
  const el = document.querySelector(sel);
  if (!el) return;

  const toCOP = () => {
    const v = el.value || '';
    // Quita sufijo moneda conocido y coloca COP
    el.value = v.replace(/\s*(ALL|USD|EUR|COP)?\s*$/i, '') + ' COP';
  };

  // Corrige cuando el usuario termina de escribir o el formateador actúa
  el.addEventListener('blur', toCOP);
  el.addEventListener('change', toCOP);
  el.addEventListener('input', () => {
    // si vuelve a aparecer ALL mientras escribe, lo corrige al vuelo
    if (/\sALL$/i.test(el.value)) toCOP();
  });

  // “Keep-alive” por si el framework reinyecta ALL después de eventos
  const id = setInterval(() => {
    if (!document.body.contains(el)) return clearInterval(id);
    if (/\sALL$/i.test(el.value)) toCOP();
  }, 400);

  // Primera corrección inmediata
  setTimeout(toCOP, 0);
})();

const toDate = (s) => s ? new Date(`${s}T00:00:00`) : null;
