}
[selector^='Status-'] .form-group > div > div:hover { filter: brightness(1.03); }
[selector^='Status-'] p { margin: 0; }

/* Ícono blanco (Font Awesome 5/6) */
[selector^='Status-'] .form-group > div > div::before {
  font-family: "Font Awesome 6 Free","Font Awesome 5 Free";
  font-weight: 900;
  font-size: 12px;
  line-height: 1;
  color: currentColor;             /* blanco */
  content: "";
}

/* CARGADO – MORADO sólido (NO azul), ícono file-upload */
[selector='Status-Cargado'] .form-group > div > div {
  --bg: #6f42c1;                   /* morado */
}
[selector='Status-Cargado'] .form-group > div > div::before {
  content: "\f574";                /* fa-file-upload */
  /* si no aparece, usar "\f093" (fa-upload) */
}

/* ACEPTADO – verde sólido, check-circle */
[selector='Status-Aceptado'] .form-group > div > div {
  --bg: #198754;                   /* success */
}
[selector='Status-Aceptado'] .form-group > div > div::before {
  content: "\f058";                /* fa-check-circle */
}

/* RECHAZADO – rojo sólido, times-circle */
[selector='Status-Rechazado'] .form-group > div > div {
  --bg: #EC5962;                   /* danger */
}
[selector='Status-Rechazado'] .form-group > div > div::before {
  content: "\f057";                /* fa-times-circle */
}

/* PENDIENTE – naranja sólido, hourglass-half */
[selector='Status-Pendiente'] .form-group > div > div {
  --bg: #fd7e14;                   /* warning */
}
[selector='Status-Pendiente'] .form-group > div > div::before {
  content: "\f252";                /* fa-hourglass-half */
}

/* Poner el texto en blanco dentro de los 4 estados */
[selector^='Status-'] p,
[selector^='Status-'] p strong {
  color: #fff !important;
  margin-bottom: 0px !important; 
}

.col-sm-3 {
  display: flex;
  flex-direction: column; /* Acomoda en columna */
  gap: 8px;               /* Espacio entre selector y observación */
}

/* Contenedor del selector completo */
[selector="Grd-List-Seleccion"] .form-group {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  text-align: center;
  margin-bottom: -5px;
}

/* El multiselect se queda en auto, no se estira */
[selector="Grd-List-Seleccion"] .form-group > .form-group {
  margin: 0 0 9px 0;   /* quita auto para que el justify-center haga el trabajo */
  flex: 0 0 auto;      /* ancho auto según contenido */
}


/* Asterisco en línea */
[selector="Grd-List-Seleccion"] .required-asterisk {
  order: -1;
}

/* 3) El mensaje de error VA ABAJO y en toda la fila */
[selector="Grd-List-Seleccion"] .invalid-feedback {
  order: 2;                 /* aparece después del control */
  flex: 0 0 100%;           /* fuerza salto de línea completo */
  display: block !important;
  margin-top: 4px;
}

[selector="Grd-Observacion"] {
  width: 90%;
}

[selector="Grd-Observacion"] .required-asterisk {
  display: none;
}

[selector="Grd-List-Seleccion"] .multiselect__input{
  border: 0 !important;
}

/* Fondo blanco semitransparente que cubre toda la pantalla */
#global-loader-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(255, 255, 255, 0.75);
  z-index: 9999;
  display: none;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Mostrar el loader */
#global-loader-overlay.show {
  display: flex;
}

/* Spinner circular con color corporativo */
#global-loader-spinner {
  width: 60px;
  height: 60px;
  border: 6px solid #e0e0e0;
  border-top: 6px solid #2167AE;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

/* Animación */
@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

.multiselect.multiselect--disabled .multiselect__tags {
  background: #f2f2f2 !important;
  border-color: #dcdcdc !important;
  color: #6c757d !important;
}

.multiselect.multiselect--disabled .multiselect__input[disabled] {
  background: #f2f2f2 !important;
  color: #6c757d !important;
  cursor: not-allowed !important;
}

.multiselect.multiselect--disabled .multiselect__input[disabled]::placeholder {
  color: #9aa0a6 !important;
}

.multiselect.multiselect--disabled .multiselect__single {
  background: #f2f2f2 !important;
  color: #6c757d !important;
  border-radius: .25rem;
}

.multiselect.multiselect--disabled,
.multiselect.multiselect--disabled .multiselect__select {
  cursor: not-allowed !important;
  opacity: 0.9;
  pointer-events: none;
}

