computed.formula:
const servicios = [
  this.frm_service_tia_status,
  this.frm_service_optalitix_status,
  this.frm_service_zdilligence_status
];

const algunoCaido = servicios.some(s => String(s || "").trim() !== "200");

return algunoCaido ? "true" : "false";
